const output = $json.output;

const forbiddenKeywords = [
  "rm -rf",
  "DROP DATABASE",
  "DELETE FROM",
  "TRUNCATE TABLE",
  "sudo rm",
  "shutdown",
  "format c:"
];

const valid = !forbiddenKeywords.some(keyword =>
  output.toLowerCase().includes(keyword.toLowerCase())
);

return [
  {
    json: {
      valid,
      repair_output: output
    }
  }
];
